package try

import (
	"context"
	"fmt"
	"net/http"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	StatusExecutionFailed  = "execution_failed"
	StatusLandConflict     = "land_conflict"
	StatusSuccess          = "success"
	StatusNoChanges        = "no_changes"
	StatusAlreadySatisfied = "already_satisfied"
)

type Report struct {
	BeadID                      string
	AttemptID                   string
	WorkerID                    string
	Harness                     string
	Provider                    string
	Model                       string
	ActualPower                 int
	Status                      string
	Detail                      string
	SessionID                   string
	BaseRev                     string
	ResultRev                   string
	PreserveRef                 string
	RetryAfter                  string
	NoChangesRationale          string
	ReviewVerdict               string
	ReviewRationale             string
	Tier                        string
	ProbeResult                 string
	CostUSD                     float64
	DurationMS                  int64
	RequestedProfile            string
	RequestedTier               string
	ResolvedTier                string
	EscalationCount             int
	FinalTier                   string
	DecompositionRecommendation []string
	DecompositionRationale      string
	Disrupted                   bool
	DisruptionReason            string
	OutcomeReason               string
	Error                       string
	Stderr                      string
	RateLimitBudget             time.Duration
}

type Executor interface {
	Execute(ctx context.Context, beadID string) (Report, error)
}

type ExecutorFunc func(ctx context.Context, beadID string) (Report, error)

func (f ExecutorFunc) Execute(ctx context.Context, beadID string) (Report, error) {
	return f(ctx, beadID)
}

type Store interface {
	AppendEvent(beadID string, ev bead.BeadEvent) error
	CloseWithEvidence(beadID, sessionID, sha string) error
	Unclaim(beadID string) error
	SetExecutionCooldown(beadID string, until time.Time, status, detail string) error
	IncrNoChangesCount(beadID string) (int, error)
}

type ConflictAutoRecoverFn func(wd, preserveRef string) (string, error)

type ConflictResolverFn func(ctx context.Context, beadID, preserveRef, projectRoot string) (newTip string, isBlocking bool, err error)

type AttemptOpts struct {
	Bead                   bead.Bead
	Executor               Executor
	Store                  Store
	ProjectRoot            string
	SatisfactionChecker    SatisfactionChecker
	VerificationRunner     VerificationCommandRunner
	AutoRecover            ConflictAutoRecoverFn
	ConflictResolver       ConflictResolverFn
	Assignee               string
	Now                    func() time.Time
	Cooldown               time.Duration
	RateLimitBudget        time.Duration
	RateLimitPerWaitCap    time.Duration
	RateLimitWaitEvaluator func(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision
	RateLimitSleep         func(ctx context.Context, d time.Duration) error
	RateLimitNow           func() time.Time
	RateLimitOnRetry       func(ctx context.Context, info RateLimitRetryInfo)
}

type Disposition string

const (
	OutcomeReported Disposition = "reported"
	OutcomeSuccess  Disposition = "merged"
	OutcomePark     Disposition = "park"
)

type Outcome struct {
	Report      Report
	Disposition Disposition
	NoChanges   *NoChangesOutcome
	StoreErrOp  string
	StoreErr    error
}

func Attempt(ctx context.Context, store Store, beadID string, opts AttemptOpts) (Outcome, error) {
	if opts.Executor == nil {
		return Outcome{}, fmt.Errorf("try attempt: executor is required")
	}
	rateCfg := resolveRateLimitRetryConfig(opts)
	var (
		report Report
		err    error
	)
	for retryCount, elapsed := 0, time.Duration(0); ; {
		report, err = opts.Executor.Execute(ctx, beadID)
		if err != nil {
			report = Report{
				BeadID: beadID,
				Status: StatusExecutionFailed,
				Detail: err.Error(),
				Error:  err.Error(),
			}
		}
		if report.BeadID == "" {
			report.BeadID = beadID
		}
		if report.Status == "" {
			report.Status = StatusExecutionFailed
		}

		rateLimited := IsRateLimitReport(&report)
		effectiveBudget := rateCfg.Budget
		if opts.RateLimitBudget == 0 && report.RateLimitBudget != 0 {
			effectiveBudget = report.RateLimitBudget
		}
		decision, retryAfter := evaluateRateLimitAttempt(report, rateCfg, retryCount+1, elapsed, effectiveBudget)
		if !decision.ShouldRetry {
			if decision.Reason != "" {
				report.Error = decision.Reason
			}
			if rateLimited && decision.Reason != "" && rateCfg.OnRetry != nil {
				rateCfg.OnRetry(ctx, RateLimitRetryInfo{
					Attempt:    retryCount + 1,
					Source:     decision.Source,
					Report:     &report,
					Elapsed:    elapsed,
					RetryAfter: retryAfter,
					OverBudget: true,
				})
			}
			break
		}

		retryCount++
		info := RateLimitRetryInfo{
			Attempt:    retryCount,
			Wait:       decision.Wait,
			Source:     decision.Source,
			Report:     &report,
			Elapsed:    elapsed,
			RetryAfter: retryAfter,
		}
		if rateCfg.OnRetry != nil {
			rateCfg.OnRetry(ctx, info)
		}
		if err := rateCfg.Sleep(ctx, decision.Wait); err != nil {
			return Outcome{}, err
		}
		elapsed += decision.Wait
	}

	if ShouldAttemptConflictRecovery(report, opts.ProjectRoot) {
		if opts.Store == nil {
			opts.Store = store
		}
		return ConflictRecoveryOutcome(ctx, ConflictRecoveryInput{
			Bead:             opts.Bead,
			Report:           report,
			ProjectRoot:      opts.ProjectRoot,
			AutoRecover:      opts.AutoRecover,
			ConflictResolver: opts.ConflictResolver,
			Store:            opts.Store,
			Assignee:         opts.Assignee,
			Now:              opts.Now,
			Cooldown:         opts.Cooldown,
		}), err
	}

	if report.Status == StatusNoChanges {
		if opts.Store == nil {
			opts.Store = store
		}
		if opts.Store == nil {
			return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: fmt.Errorf("try attempt: no_changes store is required")}, nil
		}
		noChangesCount, countErr := opts.Store.IncrNoChangesCount(beadID)
		if countErr != nil {
			return Outcome{Report: report, StoreErrOp: "IncrNoChangesCount", StoreErr: countErr}, nil
		}
		noChangesOut, adjudicatedReport, adjErr := adjudicateNoChangesContract(ctx, beadID, report, opts.ProjectRoot, noChangesCount, opts.SatisfactionChecker, opts.VerificationRunner)
		if adjErr != nil {
			return Outcome{Report: report, StoreErrOp: "adjudicateNoChanges", StoreErr: adjErr}, nil
		}
		return Outcome{
			Report:      adjudicatedReport,
			Disposition: OutcomeReported,
			NoChanges:   &noChangesOut,
		}, nil
	}

	return Outcome{Report: report, Disposition: OutcomeReported}, err
}

type RateLimitRetryConfig struct {
	Budget     time.Duration
	PerWaitCap time.Duration
	Sleep      func(ctx context.Context, d time.Duration) error
	Now        func() time.Time
	Evaluator  func(retryAfter time.Duration, attempt int, elapsed, budget, perWaitCap time.Duration) RateLimitWaitDecision
	OnRetry    func(ctx context.Context, info RateLimitRetryInfo)
}

const (
	RateLimitRetryDefaultBudget     = 5 * time.Minute
	RateLimitRetryDefaultPerWaitCap = 60 * time.Second
	RateLimitBudgetExhaustedReason  = "rate-limited beyond budget"
)

var rateLimitBackoffSchedule = []time.Duration{
	1 * time.Second,
	5 * time.Second,
	15 * time.Second,
	30 * time.Second,
	60 * time.Second,
}

type RateLimitWaitDecision struct {
	ShouldRetry bool
	Wait        time.Duration
	Source      string
	Reason      string
}

type RateLimitRetryInfo struct {
	Attempt    int
	Wait       time.Duration
	Source     string
	Report     *Report

		// Adjudication confirmed bead is already satisfied.
		// Set the terminal status BEFORE the close so the late
		// executeBeadLoopEvent append captures "already_satisfied"
		// (not "no_changes"), and emit an early execute-bead
		// evidence event so the closure gate accepts even when
		// BaseRev is empty (test fixtures and genuinely-no-commit
		// satisfied beads).
		report.Status = ExecuteBeadStatusAlreadySatisfied
		if noChanges.Evidence != "" {
			// Checker evidence explains why the bead is being closed;
			// it takes precedence over the executor's attempt detail.
			report.Detail = noChanges.Evidence
		}
		_ = w.Store.AppendEvent(candidate.ID, executeBeadLoopEvent(report, assignee, now().UTC()))
		if cerr := w.Store.CloseWithEvidence(candidate.ID, report.SessionID, report.BaseRev); cerr != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "CloseWithEvidence", cerr, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		result.Successes++
		result.LastSuccessAt = now().UTC()
	} else {
		// Unresolved: suppress immediate retry so the queue can
		// move on to other beads.
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		if shouldSuppressNoProgress(report) {
			retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))
			if cerr := w.Store.SetExecutionCooldown(candidate.ID, retryAfter, report.Status, report.Detail); cerr != nil {
				if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", cerr, assignee, result, runtime, now) {
					continue
				}
				return result, ctx.Err()
			}
			report.RetryAfter = retryAfter.Format(time.RFC3339)
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	}
} else {
	if err := w.Store.Unclaim(candidate.ID); err != nil {
		if w.handleOutcomeStoreError(ctx, candidate.ID, "Unclaim", err, assignee, result, runtime, now) {
			continue
		}
		return result, ctx.Err()
	}
	if report.Status == ExecuteBeadStatusPreservedNeedsReview {
		if err := w.Store.AppendNotes(candidate.ID, preservedNeedsReviewNote(report)); err != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "AppendNotes", err, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		result.Failures++
		result.LastFailureStatus = report.Status
	} else if report.Status == ExecuteBeadStatusDeclinedNeedsDecomposition {
		// Executor declined the bead because it is too large to
		// deliver in one pass. Record a structured
		// `decomposition-recommendation` event and park the bead
		// long enough that subsequent loop iterations do NOT
		// re-attempt it. An operator (or helix-evolve) clears the
		// cooldown — typically by splitting the bead.
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		body, mErr := json.Marshal(map[string]any{
			"rationale":            report.DecompositionRationale,
			"recommended_subbeads": report.DecompositionRecommendation,
			"detail":               report.Detail,
			"base_rev":             report.BaseRev,
			"session_id":           report.SessionID,
		})
		bodyStr := ""
		if mErr == nil {
			bodyStr = string(body)
		} else {
			bodyStr = fmt.Sprintf("rationale=%s\nrecommended_subbeads=%v",
				report.DecompositionRationale, report.DecompositionRecommendation)
		}
		summary := "agent declined: needs decomposition"
		if n := len(report.DecompositionRecommendation); n > 0 {
			summary = fmt.Sprintf("%s (%d sub-beads)", summary, n)
		}
		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:      "decomposition-recommendation",
			Summary:   summary,
			Body:      bodyStr,
			Actor:     assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
		if err := w.Store.SetExecutionCooldown(candidate.ID, parkUntil, report.Status, report.Detail); err != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", err, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		report.RetryAfter = parkUntil.Format(time.RFC3339)
		result.Failures++
		result.LastFailureStatus = report.Status
	} else if report.Status == ExecuteBeadStatusPushFailed {
		// Push failed after a successful local merge/ff. The bead is
		// NOT closed (commits live only locally) — park it under the
		// 24h cap so the loop re-attempts within a reasonable horizon.
		// The push stderr in report.Detail is recorded as last_detail
		// so it surfaces on the bead and on any direct claim attempt.
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
		if err := w.Store.SetExecutionCooldown(candidate.ID, parkUntil, report.Status, report.Detail); err != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", err, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		report.RetryAfter = parkUntil.Format(time.RFC3339)
		result.Failures++
		result.LastFailureStatus = report.Status
	} else if report.Status == ExecuteBeadStatusPushConflict {
		// The local target ref was advanced and the loop's
		// auto-pull/merge/retry recovery hit a merge conflict it
		// cannot resolve without operator input. Record a
		// `push-conflict` event with the conflict context so the
		// operator can find and resolve it, and park the bead under
		// the same 24h cap as push_failed.
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		body, mErr := json.Marshal(map[string]any{
			"detail":     report.Detail,
			"base_rev":   report.BaseRev,
			"result_rev": report.ResultRev,
			"session_id": report.SessionID,
		})
		bodyStr := report.Detail
		if mErr == nil {
			bodyStr = string(body)
		}
		_ = w.Store.AppendEvent(candidate.ID, bead.BeadEvent{
			Kind:      "push-conflict",
			Summary:   "auto-merge after push race could not be resolved",
			Body:      bodyStr,
			Actor:     assignee,
			Source:    "ddx agent execute-loop",
			CreatedAt: now().UTC(),
		})
		parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
		if err := w.Store.SetExecutionCooldown(candidate.ID, parkUntil, report.Status, report.Detail); err != nil {
			if w.handleOutcomeStoreError(ctx, candidate.ID, "SetExecutionCooldown", err, assignee, result, runtime, now) {
				continue
			}
			return result, ctx.Err()
		}
		report.RetryAfter = parkUntil.Format(time.RFC3339)
		result.Failures++
		result.LastFailureStatus = report.Status
	} else {
		report = w.runPostAttemptTriage(ctx, candidate, report, runtime, assignee, now)
		if shouldSuppressNoProgress(report) {
			retryAfter := now().UTC().Add(CapLoopCooldown(noProgressCooldown))

package agent

import (
	"context"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestClassifyExecuteBeadStatusPushFailed pins the contract that a merged
// outcome whose reason carries the push-failure marker classifies as
// push_failed (not success), so the execute-loop refuses to close the bead.
func TestClassifyExecuteBeadStatusPushFailed(t *testing.T) {
	got := ClassifyExecuteBeadStatus("merged", 0, PushFailedReasonPrefix+" remote rejected: pre-receive hook declined")
	assert.Equal(t, ExecuteBeadStatusPushFailed, got,
		"merged outcome with push-failed reason must classify as push_failed, not success")

	gotMerged := ClassifyExecuteBeadStatus("merged", 0, "merged onto current tip")
	assert.Equal(t, ExecuteBeadStatusSuccess, gotMerged,
		"merged outcome without push-failed reason must still classify as success")
}

func TestClassifyExecuteBeadStatusPreservedNeedsReview(t *testing.T) {
	for _, reason := range []string{
		"large-deletion gate: huge.txt deleted 250 lines (threshold 200)",
		"syntax sanity gate: config.json: invalid JSON",
		"post-land gate failed: make test: exit status 2",
	} {
		got := ClassifyExecuteBeadStatus("preserved", 0, reason)
		assert.Equal(t, ExecuteBeadStatusPreservedNeedsReview, got, reason)
	}
}

// TestExecuteBeadWorkerPushFailedStaysOpenAndParks asserts the AC for
// ddx-af54ebf3:
//   - bead is NOT closed (status remains open)
//   - last_status=push_failed and the push stderr are stored as cooldown metadata
//   - the bead's events surface the push stderr so an operator can see it
func TestExecuteBeadWorkerPushFailedStaysOpenAndParks(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	pushStderr := "remote: error: GH001: large files detected; aborting"
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusPushFailed,
				Detail:    PushFailedReasonPrefix + " " + pushStderr,
				SessionID: "sess-push-failed",
				BaseRev:   "aaaa1111",
				ResultRev: "bbbb2222",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.GreaterOrEqual(t, result.Failures, 1)
	assert.Equal(t, ExecuteBeadStatusPushFailed, result.LastFailureStatus)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "push_failed must NOT close the bead")
	assert.Empty(t, got.Owner, "push_failed must release the claim")

	require.NotNil(t, got.Extra)
	assert.Equal(t, "push_failed", got.Extra["execute-loop-last-status"],
		"loop must record last_status=push_failed so subsequent claim attempts can refuse")
	detail, _ := got.Extra["execute-loop-last-detail"].(string)
	assert.Contains(t, detail, pushStderr,
		"loop must record the push stderr in last_detail so operators can see why")
	assert.NotEmpty(t, got.Extra["execute-loop-retry-after"],
		"push_failed must park the bead via execute-loop-retry-after")

	events, err := store.Events(first.ID)
	require.NoError(t, err)
	require.NotEmpty(t, events)
	var sawPushStderr bool
	for _, ev := range events {
		if ev.Summary == ExecuteBeadStatusPushFailed && strings.Contains(ev.Body, pushStderr) {
			sawPushStderr = true
			break
		}
	}
	assert.True(t, sawPushStderr,
		"push stderr must appear in a bead event so operators can see why the push failed")
}

// TestExecuteBeadWorkerPushFailedCooldownCappedAt24h pins AC #2 + #7 of
// ddx-a458af7c: push_failed (and every other loop-set cooldown) caps at
// MaxLoopCooldown (24h). Year-scale parks are an operator decision via
// `ddx bead update --set execute-loop-retry-after=...`, never an automatic
// loop output.
func TestExecuteBeadWorkerPushFailedCooldownCappedAt24h(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusPushFailed,
				Detail:    PushFailedReasonPrefix + " remote rejected",
				SessionID: "sess-cap",
				BaseRev:   "aaaa",
				ResultRev: "bbbb",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	startedAt := time.Now().UTC()
	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	retryAfter, _ := got.Extra["execute-loop-retry-after"].(string)
	require.NotEmpty(t, retryAfter, "push_failed must park the bead")
	parsed, perr := time.Parse(time.RFC3339, retryAfter)
	require.NoError(t, perr, "execute-loop-retry-after must parse as RFC3339")
	delta := parsed.Sub(startedAt)
	assert.LessOrEqual(t, delta, MaxLoopCooldown+time.Minute,
		"push_failed cooldown must cap at MaxLoopCooldown (24h), got %s", delta)
}

// TestExecuteBeadWorkerPushConflictParksAndEmitsEvent pins AC #3 + #5 of
// ddx-a458af7c: push_conflict (auto-merge during push recovery failed)
// emits a structured `push-conflict` event, parks the bead under the 24h
// cap, and is distinct from generic execution_failed.
func TestExecuteBeadWorkerPushConflictParksAndEmitsEvent(t *testing.T) {
	store, first, _ := newExecuteLoopTestStore(t)
	conflictDetail := PushConflictReasonPrefix + " auto-recovery retry push: CONFLICT (content)"
	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (ExecuteBeadReport, error) {
			return ExecuteBeadReport{
				BeadID:    beadID,
				Status:    ExecuteBeadStatusPushConflict,
				Detail:    conflictDetail,
				SessionID: "sess-pconf",
				BaseRev:   "aaaa1111",
				ResultRev: "cccc3333",
			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	startedAt := time.Now().UTC()
	result, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{Once: true})
	require.NoError(t, err)
	require.NotNil(t, result)
	assert.Equal(t, ExecuteBeadStatusPushConflict, result.LastFailureStatus)

	got, err := store.Get(first.ID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusOpen, got.Status, "push_conflict must NOT close the bead")
	require.NotNil(t, got.Extra)
	assert.Equal(t, "push_conflict", got.Extra["execute-loop-last-status"])

	// Cooldown capped at 24h.
	retryAfter, _ := got.Extra["execute-loop-retry-after"].(string)
	require.NotEmpty(t, retryAfter)
	parsed, perr := time.Parse(time.RFC3339, retryAfter)
	require.NoError(t, perr)
	delta := parsed.Sub(startedAt)
	assert.LessOrEqual(t, delta, MaxLoopCooldown+time.Minute,
		"push_conflict cooldown must cap at MaxLoopCooldown (24h), got %s", delta)

	// Structured push-conflict event with the conflict context.
	events, err := store.Events(first.ID)
	require.NoError(t, err)
	var sawPushConflict bool
	for _, ev := range events {
		if ev.Kind == "push-conflict" {
			sawPushConflict = true
			assert.Contains(t, ev.Body, conflictDetail,
				"push-conflict event body must record the conflict detail")
			break
		}
	}
	assert.True(t, sawPushConflict,
		"loop must emit a kind:push-conflict event so operators can see the conflict context")
}

// TestClaimRefusesPushFailedBead pins the AC that subsequent claim attempts
// on a push-failed bead fail loudly until the operator clears
// execute-loop-last-status.
func TestClaimRefusesPushFailedBead(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	b := &bead.Bead{ID: "ddx-pf01", Title: "push-failed", Priority: 0}
	require.NoError(t, store.Create(b))

	require.NoError(t, store.Update(b.ID, func(bb *bead.Bead) {
		if bb.Extra == nil {
			bb.Extra = map[string]any{}
		}
		bb.Extra["execute-loop-last-status"] = "push_failed"
		bb.Extra["execute-loop-last-detail"] = PushFailedReasonPrefix + " remote: GH001: large files detected"
	}))

	err := store.Claim(b.ID, "worker")
	require.Error(t, err, "Claim must refuse a bead whose last_status=push_failed")
	assert.Contains(t, err.Error(), "push failed")
	assert.Contains(t, err.Error(), "GH001",
		"the previous push stderr must surface in the claim error so it fails loudly")

	// Clearing the last_status restores claimability.
	require.NoError(t, store.Update(b.ID, func(bb *bead.Bead) {
		delete(bb.Extra, "execute-loop-last-status")
		delete(bb.Extra, "execute-loop-last-detail")
	}))
	require.NoError(t, store.Claim(b.ID, "worker"),
		"Claim must succeed after operator clears execute-loop-last-status")
}

