package try

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

const (
	StatusLandConflictUnresolvable = "land_conflict_unresolvable"
	StatusLandConflictNeedsHuman   = "land_conflict_needs_human"
)

type ConflictRecoveryDisposition int

const (
	ConflictRecoveryMerged ConflictRecoveryDisposition = iota
	ConflictRecoveryPark
	ConflictRecoveryNeedsHuman
)

type ConflictRecoveryInput struct {
	Bead             bead.Bead
	Report           Report
	ProjectRoot      string
	AutoRecover      ConflictAutoRecoverFn
	ConflictResolver ConflictResolverFn
	Store            Store
	Assignee         string
	Now              func() time.Time
	Cooldown         time.Duration
}

type ConflictRecoveryOutput struct {
	Report      Report
	Disposition ConflictRecoveryDisposition
	StoreErrOp  string
	StoreErr    error
}

func ConflictRecoveryOutcome(ctx context.Context, in ConflictRecoveryInput) Outcome {
	out := RunConflictRecovery(ctx, in)
	disposition := OutcomePark
	if out.Disposition == ConflictRecoveryMerged {
		disposition = OutcomeSuccess
	}
	return Outcome{
		Report:      out.Report,
		Disposition: disposition,
		StoreErrOp:  out.StoreErrOp,
		StoreErr:    out.StoreErr,
	}
}

func RunConflictRecovery(ctx context.Context, in ConflictRecoveryInput) ConflictRecoveryOutput {
	report := in.Report
	out := ConflictRecoveryOutput{Report: report}

	now := in.Now
	if now == nil {
		now = time.Now
	}

	autoFn := in.AutoRecover
	if autoFn == nil {
		autoFn = func(string, string) (string, error) {
			return "", fmt.Errorf("conflict auto-recover function is required")
		}
	}

	newTip, autoErr := autoFn(in.ProjectRoot, report.PreserveRef)
	if autoErr == nil && newTip != "" {
		_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
			Kind:      "land-conflict-auto-recovered",
			Summary:   "preserved iteration auto-recovered onto current tip via ort",
			Body:      fmt.Sprintf("preserve_ref=%s\nnew_tip=%s", report.PreserveRef, newTip),
			Actor:     in.Assignee,
			Source:    "ddx agent try",
			CreatedAt: now().UTC(),
		})
		report.Status = StatusSuccess
		report.ResultRev = newTip
		report.Detail = "auto-recovered: merged preserved iteration onto current tip via ort"
		if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
			out.StoreErrOp = "CloseWithEvidence"
			out.StoreErr = err
			out.Report = report
			return out
		}
		out.Report = report
		out.Disposition = ConflictRecoveryMerged
		return out
	}

	if in.ConflictResolver != nil {
		resolvedTip, isBlocking, resolveErr := in.ConflictResolver(ctx, in.Bead.ID, report.PreserveRef, in.ProjectRoot)
		if resolveErr == nil && resolvedTip != "" {
			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
				Kind:      "land-conflict-auto-recovered",
				Summary:   "preserved iteration resolved by focused conflict-resolve agent",
				Body:      fmt.Sprintf("preserve_ref=%s\nnew_tip=%s", report.PreserveRef, resolvedTip),
				Actor:     in.Assignee,
				Source:    "ddx agent try",
				CreatedAt: now().UTC(),
			})
			report.Status = StatusSuccess
			report.ResultRev = resolvedTip
			report.Detail = "auto-recovered: focused conflict-resolve agent landed preserved iteration"
			if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
				out.StoreErrOp = "CloseWithEvidence"
				out.StoreErr = err
				out.Report = report
				return out
			}
			out.Report = report
			out.Disposition = ConflictRecoveryMerged
			return out
		}
		if isBlocking {
			report.Status = StatusLandConflictNeedsHuman
		} else {
			report.Status = StatusLandConflictUnresolvable
		}
	} else {
		report.Status = StatusLandConflictUnresolvable
	}

	autoErrMsg := ""
	if autoErr != nil {
		autoErrMsg = autoErr.Error()
	}
	body, mErr := json.Marshal(map[string]any{
		"preserve_ref":     report.PreserveRef,
		"base_rev":         report.BaseRev,
		"result_rev":       report.ResultRev,
		"session_id":       report.SessionID,
		"auto_merge_error": autoErrMsg,
	})
	bodyStr := report.PreserveRef
	if mErr == nil {
		bodyStr = string(body)
	}
	eventKind := "land-conflict-unresolvable"
	if report.Status == StatusLandConflictNeedsHuman {
		eventKind = "land-conflict-needs-human"
	}
	_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
		Kind:      eventKind,
		Summary:   "preserved iteration could not be auto-recovered; parked for operator",
		Body:      bodyStr,
		Actor:     in.Assignee,
		Source:    "ddx agent try",
		CreatedAt: now().UTC(),
	})
	report.Detail = report.Status + ": preserve_ref=" + report.PreserveRef

	if err := in.Store.Unclaim(in.Bead.ID); err != nil {
		out.StoreErrOp = "Unclaim"
		out.StoreErr = err
		out.Report = report
		return out
	}
	parkUntil := now().UTC().Add(in.Cooldown)
	if err := in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, report.Status, report.Detail); err != nil {
		out.StoreErrOp = "SetExecutionCooldown"
		out.StoreErr = err
		out.Report = report
		return out
	}
	report.RetryAfter = parkUntil.Format(time.RFC3339)

	out.Report = report
	if report.Status == StatusLandConflictNeedsHuman {
		out.Disposition = ConflictRecoveryNeedsHuman
	} else {
		out.Disposition = ConflictRecoveryPark
	}
	return out
}

}

// Worker-level outcome constants — set by ExecuteBead() on the result.
// The parent orchestrator (LandBeadResult + ApplyLandingToResult) then
// overwrites Outcome and Status with the landing decision.
const (
	ExecuteBeadOutcomeTaskSucceeded  = "task_succeeded"
	ExecuteBeadOutcomeTaskFailed     = "task_failed"
	ExecuteBeadOutcomeTaskNoChanges  = "task_no_changes"
	ExecuteBeadOutcomeTaskNoEvidence = "task_no_evidence"
)

// Status constants — used by the loop and other consumers of ExecuteBeadReport.
// These map to specific close/unclaim behaviors in ExecuteBeadWorker.
const (
	ExecuteBeadStatusStructuralValidationFailed = "structural_validation_failed"
	ExecuteBeadStatusExecutionFailed            = "execution_failed"
	ExecuteBeadStatusPostRunCheckFailed         = "post_run_check_failed"
	ExecuteBeadStatusRatchetFailed              = "ratchet_failed"
	ExecuteBeadStatusLandConflict               = "land_conflict"
	ExecuteBeadStatusPushFailed                 = "push_failed"
	ExecuteBeadStatusPushConflict               = "push_conflict"
	ExecuteBeadStatusPreservedNeedsReview       = "preserved_needs_review"
	ExecuteBeadStatusNoEvidenceProduced         = "no_evidence_produced"
	ExecuteBeadStatusNoChanges                  = "no_changes"
	ExecuteBeadStatusAlreadySatisfied           = "already_satisfied"
	ExecuteBeadStatusSuccess                    = "success"

	// ExecuteBeadStatusDeclinedNeedsDecomposition is a structured outcome
	// signalling that the executor inspected the bead and concluded it cannot
	// be delivered in a single pass — typically because the scope is
	// epic-sized and must first be broken into sub-beads. It is distinct
	// from no_changes (which means "I tried and there was nothing to change")
	// and from execution_failed (which means the agent or harness errored).
	//
	// The loop treats this status as terminal-for-loop: it parks the bead
	// with a long cooldown and records the recommended sub-beads as a
	// structured `decomposition-recommendation` event. No further attempts
	// happen until an operator clears the cooldown (e.g. via
	// `ddx bead cooldown clear`) or splits the bead.
	ExecuteBeadStatusDeclinedNeedsDecomposition = "declined_needs_decomposition"

	// Post-merge review outcomes. The bead was merged, then reviewed;
	// the review returned a non-APPROVE verdict and the bead was reopened.
	ExecuteBeadStatusReviewRequestChanges = "review_request_changes"
	ExecuteBeadStatusReviewBlock          = "review_block"
	ExecuteBeadStatusReviewMalfunction    = "review_malfunction"

	// ExecuteBeadStatusLandConflictUnresolvable is set when execute-loop
	// attempted 3-way ort auto-resolution and (if configured) a focused
	// conflict-resolve agent run for a preserved iteration, and both failed.
	// The bead is parked under LandConflictCooldown for operator review.
	ExecuteBeadStatusLandConflictUnresolvable = "land_conflict_unresolvable"

	// ExecuteBeadStatusLandConflictNeedsHuman is set when the focused
	// conflict-resolve agent escalated to BLOCKING — the conflict requires
	// human judgment, not automated retry. Parked under the same short
	// cooldown with a kind:land-conflict-needs-human event.
	ExecuteBeadStatusLandConflictNeedsHuman = "land_conflict_needs_human"
)

// ClassifyExecuteBeadStatus maps a landing outcome to the supervisor-visible
// status contract. This is called by ApplyLandingToResult and by callers who
// build an ExecuteBeadReport from a landing result.
func ClassifyExecuteBeadStatus(outcome string, exitCode int, reason string) string {
	if exitCode != 0 {
		return ExecuteBeadStatusExecutionFailed
	}

	switch outcome {
	case "merged":
		// A merged outcome whose reason carries the push-failure marker
		// means the local target branch advanced but `git push` rejected the
		// new tip (large blob, branch protection, auth, divergence, etc.).
		// Classify these as push_failed so the loop refuses to close the
		// bead and operators are forced to investigate.
		if strings.HasPrefix(reason, PushConflictReasonPrefix) {
			return ExecuteBeadStatusPushConflict
		}
		if strings.HasPrefix(reason, PushFailedReasonPrefix) {
			return ExecuteBeadStatusPushFailed
		}
		return ExecuteBeadStatusSuccess
	case "no-changes", ExecuteBeadOutcomeTaskNoChanges:
		return ExecuteBeadStatusNoChanges
	case "no-evidence", ExecuteBeadOutcomeTaskNoEvidence:
		return ExecuteBeadStatusNoEvidenceProduced
	case "error":
		return ExecuteBeadStatusExecutionFailed
	case "preserved":
		switch reason {
		case "merge conflict", "merge failed", "ff-merge not possible":
			return ExecuteBeadStatusLandConflict
		case "post-run checks failed":
			return ExecuteBeadStatusPostRunCheckFailed
		case RatchetPreserveReason:
			return ExecuteBeadStatusRatchetFailed
		case OperatorCancelReason:
			return ExecuteBeadStatusPreservedNeedsReview
		default:
			if isPreservedNeedsReviewReason(reason) {
				return ExecuteBeadStatusPreservedNeedsReview
			}
			// Preserved iterations may still be success when the caller
			// explicitly requested no merge.
			return ExecuteBeadStatusSuccess
		}
	case ExecuteBeadOutcomeTaskSucceeded:
		return ExecuteBeadStatusSuccess
	case ExecuteBeadOutcomeTaskFailed:
		return ExecuteBeadStatusExecutionFailed
	default:
		return ExecuteBeadStatusExecutionFailed
	}
}

func isPreservedNeedsReviewReason(reason string) bool {
	for _, prefix := range []string{
		"large-deletion gate:",
		"syntax sanity gate:",
		"post-land gate failed:",
	} {
		if strings.HasPrefix(reason, prefix) {
			return true
		}
	}
	return false
}

